mapper.select:
select d.id as dish_id, d.name as dish_name, d.pic, d.detail, d.meal_type, d.flavor_tags, (select departure from flight_info where id = #{flightId}) as route_departure, (select destination from flight_info where id = #{flightId}) as route_destination, 0 as score, 0 as fallback_level from dish d
d.status = 1 and ifnull(d.stock, 0) > 0
and d.meal_type = #{mealType}
and d.flavor_tags like concat('%', #{flavor}, '%')
and exists ( select 1 from flight_route_dish frd where frd.dish_id = d.id and frd.departure = (select departure from flight_info where id = #{flightId}) and frd.destination = (select destination from flight_info where id = #{flightId})
and (case when ifnull(frd.cabin_type, 3) = 0 then 3 else ifnull(frd.cabin_type, 3) end) in
#{cabinType}
and (case when ifnull(frd.cabin_type, 3) = 0 then 3 else ifnull(frd.cabin_type, 3) end) = 3
)
order by d.id desc limit #{limit}

mapper.update:
update flight_service_rating
set rating_status = 'DEFERRED',
        defer_count = ifnull(defer_count, 0) + 1,
        last_visible_at = #{now},
        next_remind_at = #{nextRemindAt},
        update_time = #{now}
where user_id = #{userId}
    and flight_id = #{flightId}
    and rating_status in ('PENDING', 'DEFERRED')
    and (expire_at is null or expire_at > #{now})

update recommendation_log rl
inner join flight_service_rating fr on fr.source_log_id = rl.id
set rl.user_rating = #{rating}
where fr.user_id = #{userId}
    and fr.flight_id = #{flightId}
    and fr.rating_status = 'SUBMITTED'

mapper.select:
select user_id as userId, flight_id as flightId, recommended_dishes as recommendedDishes, user_rating as userRating, user_feedback as userFeedback, create_time as createTime from recommendation_log where user_id is not null and (#{days} is null or create_time >= date_sub(now(), interval #{days} day)) order by create_time desc
limit #{limit}
limit 8000

select d.id as dishId, d.name as dishName, count(rl.id) as selectCount from dish d left join recommendation_log rl on ( rl.user_feedback like concat('%dishId=', d.id, '%') or rl.recommended_dishes like concat('%\"', d.name, '\"%') or rl.recommended_dishes like concat('%', d.name, '%') or rl.recommended_dishes regexp concat('(^|[^0-9])', d.id, '([^0-9]|$)') ) and ( rl.user_feedback like 'MANUAL_SELECTED%' or rl.user_feedback like 'AUTO_SELECTED_OVERDUE%' )
and rl.create_time >= #{startTime}
and rl.create_time <= #{endTime}
where d.status = 1 group by d.id, d.name having count(rl.id) > 0 order by selectCount desc, d.id desc limit #{limit}

mapper.update:
update meal_selection
set status = #{status},
    update_time = #{updateTime}
where user_id = #{userId}
  and flight_id = #{flightId}
            and meal_order = #{mealOrder}

mapper.select:
select count(1)
from meal_selection
where user_id = #{userId}
  and flight_id = #{flightId}
            and meal_order = #{mealOrder}

mapper.update:
update recommendation_log
set user_rating = #{rating}
where id = (
    select id
    from (
        select rl.id
        from recommendation_log rl
        where rl.user_id = #{userId}
          and rl.flight_id = #{flightId}
          and rl.user_feedback like 'MANUAL_SELECTED%'
                            and (
                                        rl.user_feedback like concat('%mealOrder=', #{mealOrder}, '%')
                                        or (#{mealOrder} = 1 and rl.user_feedback not like '%mealOrder=%')
                            )
        order by rl.id desc
        limit 1
    ) latest
)

update flight_service_rating
set rating_status = 'EXPIRED',
    update_time = #{now}
where id = #{id}

